import torch
import torch.nn as nn
from transformers import AutoModel

class StatsPooling(nn.Module):
    def forward(self, x):
        mean = x.mean(dim=1)
        std = x.std(dim=1, unbiased=False)
        return torch.cat((mean, std), dim=1)

class SpoofDetector(nn.Module):
    def __init__(self, pretrained_model='microsoft/wavlm-large'):
        super().__init__()
        self.encoder = AutoModel.from_pretrained(pretrained_model)
        self.pretrained_name = pretrained_model
        hidden_size = self.encoder.config.hidden_size
        self.pooling = StatsPooling()
        self.classifier = nn.Sequential(
            nn.Linear(hidden_size * 2, 256),
            nn.BatchNorm1d(256),
            nn.ReLU(inplace=True),
            nn.Dropout(0.3),
            nn.Linear(256, 1)
        )

    def forward(self, input_values, attention_mask=None):
        outputs = self.encoder(input_values, attention_mask=attention_mask)
        hidden_states = outputs.last_hidden_state
        pooled = self.pooling(hidden_states)
        logits = self.classifier(pooled)
        return logits.squeeze(-1)

    def get_pretrain_name(self):
        return self.pretrained_name
